const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const { parse } = require('path');

exports.handler = async (event) => {
    try {
        const bucket = event.Records[0].s3.bucket.name;
        const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
        
        // Validate bucket name and key
        if (!isValidBucketName(bucket) || !isValidKey(key)) {
            throw new Error('Invalid bucket name or key');
        }

        const params = {
            Bucket: bucket,
            Key: key,
        };

        const data = await s3.getObject(params).promise();
        const fileContent = data.Body.toString('utf-8');

        // Process the file content (dummy processing here)
        const processedContent = processFileContent(fileContent);

        const outputBucket = process.env.OUTPUT_BUCKET; // Ensure OUTPUT_BUCKET is set in Lambda environment variables
        const outputKey = `${parse(key).name}-processed${parse(key).ext}`;

        const uploadParams = {
            Bucket: outputBucket,
            Key: outputKey,
            Body: processedContent,
            ContentType: 'text/plain', // Adjust based on your file type
        };

        await s3.putObject(uploadParams).promise();
        return { statusCode: 200, body: 'File processed successfully' };
    } catch (error) {
        console.error('Error processing file:', error);
        return { statusCode: 500, body: 'Error processing file' };
    }
};

function isValidBucketName(bucket) {
    const bucketNameRegex = /^[a-z0-9.-]{3,63}$/; // Basic validation
    return bucketNameRegex.test(bucket);
}

function isValidKey(key) {
    return typeof key === 'string' && key.length > 0;
}

